package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  @Test
  void newFactory_createReturnsAdapterForMatchingType() {
    // Arrange
    TypeToken<String> typeToken = TypeToken.get(String.class);
    @SuppressWarnings("unchecked")
    TypeAdapter<String> mockAdapter = mock(TypeAdapter.class);

    TypeAdapterFactory factory = TypeAdapters.newFactory(typeToken, mockAdapter);

    Gson mockGson = mock(Gson.class);

    // Act
    TypeAdapter<String> adapter = factory.create(mockGson, TypeToken.get(String.class));

    // Assert
    assertSame(mockAdapter, adapter);
  }

  @Test
  void newFactory_createReturnsNullForNonMatchingType() {
    // Arrange
    TypeToken<String> typeToken = TypeToken.get(String.class);
    @SuppressWarnings("unchecked")
    TypeAdapter<String> mockAdapter = mock(TypeAdapter.class);

    TypeAdapterFactory factory = TypeAdapters.newFactory(typeToken, mockAdapter);

    Gson mockGson = mock(Gson.class);

    // Act
    TypeAdapter<Integer> adapter = factory.create(mockGson, TypeToken.get(Integer.class));

    // Assert
    assertNull(adapter);
  }
}
